// 实现 useMergedConfig
function useMergedConfig<T>(config: boolean | T): [boolean, T] {
  const enable = Boolean(config);
  const mergedConfig = React.useMemo(() => {
    if (config === true) return {} as T;
    if (config === false) return {} as T;
    return config || ({} as T);
  }, [config]);
  return [enable, mergedConfig];
}
